import{_ as e,o as a,c as t,j as r,a as p,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"小动物- 狗","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/7.载具及随从/随从/7.系列随从/小动物之友/小动物/小动物- 狗.md","filePath":"4.资源分区/7.物品与装备/7.载具及随从/随从/7.系列随从/小动物之友/小动物/小动物- 狗.md"}'),s={name:"4.资源分区/7.物品与装备/7.载具及随从/随从/7.系列随从/小动物之友/小动物/小动物- 狗.md"};function o(d,b,_,l,i,c){return a(),t("div",null,[...b[0]||(b[0]=[r("h1",{id:"小动物-狗",tabindex:"-1"},[p("小动物- 狗 "),r("a",{class:"header-anchor",href:"#小动物-狗","aria-label":'Permalink to "小动物- 狗"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风021")])])],-1),n('<h1 id="小动物-狗-1" tabindex="-1">小动物- 狗 <a class="header-anchor" href="#小动物-狗-1" aria-label="Permalink to &quot;小动物- 狗&quot;">​</a></h1><p>狗狗<br> 无支线随从<br> 250分<br> 动物种类：犬科动物<br> 狗，是食肉目犬科 犬属哺乳动物，别称犬，与马、牛、羊、猪和鸡并称“六畜”。狗的体型大小、毛色因品种不同而不同，体格匀称；鼻吻部较长；眼呈卵圆形；两耳或竖或垂；四肢矫健，前肢5趾，后肢4趾，具爪，但爪不能伸缩；尾呈环形或镰刀形。据李时珍《本草纲目》记载：“狗，叩的意思。狗吠声有节奏，如同叩击物体一般，也有人说是因其苟且，故称之为狗。”<br> 随从外貌：根据自我喜欢去选择一种犬类，然后把对于犬类的外貌描述填入这里<br> 基础外貌：3<br> 基础体型：1-4（根据你自己选择的犬类体型自己进行填写）<br> 随从属性：<br> 生理属性<br> 力量：5<br> 敏捷：3<br> 耐力：5<br> 心智属性<br> 智力：1<br> 感知：1<br> 决心：3<br> 互动属性<br> 风度：3<br> 操控：1<br> 沉着：1</p><p>技能<br> 生理系<br> 运动3<br> 专业：反射3<br> 求生3<br> 专业：强韧1 追踪3<br> 射击1<br> 专业：<br> 武技1<br> 专业：爪击1</p><p>心智系<br> 学识1<br> 专业：爪子精通1<br> 器用1<br> 专业：<br> 手艺1<br> 专业：<br> 专注1<br> 专业：意志1</p><p>互动系<br> 洞察1<br> 专业：侦查1<br> 隐秘1<br> 专业：<br> 表达1<br> 专业：<br> 社交1<br> 专业</p><p>衍生属性值<br> 体积<br> 速度 （力量【5】+敏捷【3】+体积【1-4】+每1点敏捷上的附加获得3移动速度）=9-12（根据你选择的犬类大小进行填写）<br> 先攻 （敏捷【3】+沉着【1】）= 4<br> 防御 （敏捷感知的平均值【2】+较高者的附加成功【】）=2<br> 生命值 （耐力【5】+体积【1-4】+耐力附加【 】×5）=6-9（根据你选的犬类大小进行填写）<br> 意志力池 （决心【3】+沉着【1】+决心附加【 】×2）=4<br> 意志 （决心【3】+专注+意志【2】）= 5<br> 反射 （敏捷【3】+运动+反射【6】）= 9+1<br> 强韧 （耐力【5】+生存+强韧【4+1】）= 9+1<br> 侦查 （感知【1】+洞察+侦查【2】）= 3<br> 敏感范围 （感知【1】*20米+感知上的附加成功【 】*20米）=20米</p><p>攻击预设：8<br> 基础DP：5（力量）+1（武技）+1（爪击）+1（爪子精通）=8<br> 非常态项：<br> 破防效果：<br> 附加成功：<br> 非常态项：<br> 攻击特殊效果：</p><p>防御预设：<br> 基础防御：2<br> 附加成功：无<br> 额外效果：<br> 防御类型：<br> 附加成功：<br> 额外效果：</p><p>豁免项：<br> 意志豁免：5<br> 附加成功：<br> 反射豁免：9<br> 附加成功：1<br> 强韧豁免：9<br> 附加成功：1</p><p>免疫项：</p><p>专长：</p><p>装备位：<br> 头部-面具/头盔（会被狗狗带在头上但是因为脸部无法带面具所以一般面具无法佩戴）<br> 颈部-护符 （会变成项链吊坠项圈这种类似在狗狗的脖子上）<br> 上肢-躯干 （会被当做衣服穿在狗狗的身上）<br> 肩部-斗篷 （会在脖子上，但是会跟颈部装备产生冲突）<br> 上肢-爪子 （给爪子上特殊的武装，但是不能持握武器）<br> 手部-手腕 （给狗狗的四条腿上挂上腕带类似，戴上一个可以选择四条腿都有一样的画风，但是依旧只有一个装备位）<br> 下肢-鞋袜 （给狗狗的爪子穿上鞋袜但是因此会跟爪子产生冲突）</p><hr><p>Copyright ? 2024 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',14)])])}const m=e(s,[["render",o]]);export{f as __pageData,m as default};
